${pagingTop} SELECT TID, LIB_CODE, UUID, MAJOR, MINOR, DISTANCE, TYPE, CONTENT , URL, UDATE, ATCH_FILE_ID, MOD_ID, MOD_NM, MOD_IP, PLACE_INFO , (SELECT MIN(HOMEPAGE_NAME) FROM CMS_HOMEPAGE WHERE substr(HOMEPAGE_CODE, 0, 8) = a.LIB_CODE GROUP BY HOMEPAGE_CODE) AS LIB_NAME FROM gbesearch.CHT_BEACON_TBL a WHERE 1 = 1
AND ${search_type} LIKE '%'||#{search_text}||'%'
AND lib_code = #{lib_code} UNION ALL SELECT TID, LIB_CODE, UUID, MAJOR, MINOR, DISTANCE, TYPE, CONTENT , URL, UDATE, ATCH_FILE_ID, MOD_ID, MOD_NM, MOD_IP, PLACE_INFO , (SELECT MIN(HOMEPAGE_NAME) FROM CMS_HOMEPAGE WHERE substr(HOMEPAGE_CODE, 0, 8) = a.LIB_CODE GROUP BY HOMEPAGE_CODE) AS LIB_NAME FROM gbesearch.CHT_BEACON_TBL a WHERE 1 = 1
AND ${search_type} LIKE '%'||#{search_text}||'%'
AND lib_code != #{lib_code}
${pagingBottom}

mapper.insert:

	SELECT gbesearch.SEQ_BEACON.NEXTVAL FROM DUAL

INSERT INTO gbesearch.CHT_BEACON_TBL
(
	TID, LIB_CODE, UUID, MAJOR, MINOR, DISTANCE, TYPE, CONTENT, URL, UDATE, ATCH_FILE_ID, MOD_ID, MOD_NM, MOD_IP, PLACE_INFO
) VALUES
( 
	#{tid}, #{lib_code}, #{uuid}, #{major}, #{minor}, #{distance}, #{type}, #{content}, #{url}, SYSDATE, #{atch_file_id}, #{mod_id}, #{mod_nm}, #{mod_ip}, #{place_info}
)

mapper.update:
UPDATE
	gbesearch.CHT_BEACON_TBL
SET
	LIB_CODE 		= #{lib_code}
	, MINOR			= #{minor}
	, TYPE			= #{type}
	, CONTENT		= #{content}

	, URL			= #{url}

	, UDATE			= SYSDATE
	, ATCH_FILE_ID	= #{atch_file_id}
	, MOD_ID		= #{mod_id}
	, MOD_NM		= #{mod_nm}
	, MOD_IP		= #{mod_ip}
	, PLACE_INFO	= #{place_info}
WHERE
	TID = #{tid}

mapper.select:
SELECT COUNT(*)
FROM gbesearch.CHT_BEACON_TBL
WHERE MINOR = #{minor} AND TID != #{tid}

